import asyncio, logging, socket, webbrowser, json as _json, hashlib
from datetime import datetime
from pathlib import Path
from aiohttp import web

logger = logging.getLogger(__name__)

PROFILE_PREFIX = "__SP__"
FILE_PREFIX    = "__SF__"
GROUP_PREFIX   = "__SG__"
CALL_PREFIX    = "SC"
CALL_PREFIX    = "\x00SC\x00"

LOGO_DATA = "data:image/png;base64,"

def _ts(ts): return datetime.fromtimestamp(ts).strftime("%H:%M")
def _my_ip():
    try:
        s=socket.socket(socket.AF_INET,socket.SOCK_DGRAM); s.connect(("8.8.8.8",80)); ip=s.getsockname()[0]; s.close(); return ip
    except: return "127.0.0.1"

def _hash_password(password):
    return hashlib.sha256(password.encode()).hexdigest()

def _accounts_path():
    p = Path.home() / ".p2p_messenger" / "accounts.json"
    p.parent.mkdir(mode=0o700, exist_ok=True)
    return p

def _load_accounts():
    p = _accounts_path()
    if p.exists():
        try: return _json.loads(p.read_text("utf-8"))
        except: pass
    return {}

def _save_accounts(accounts):
    _accounts_path().write_text(_json.dumps(accounts, ensure_ascii=False, indent=2), "utf-8")

